import{_ as o,c as a,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Быстрый старт: функции оркестрации | oh-my-opencode","description":"Быстро установите и начните использовать oh-my-opencode. Изучите основные возможности оркестрации и режим Ultrawork. Завершите установку и базовую настройку за 5 минут.","frontmatter":{"title":"Быстрый старт: функции оркестрации | oh-my-opencode","sidebarTitle":"5 минут для начала","subtitle":"Быстрый старт: функции оркестрации","description":"Быстро установите и начните использовать oh-my-opencode. Изучите основные возможности оркестрации и режим Ultrawork. Завершите установку и базовую настройку за 5 минут.","order":10},"headers":[],"relativePath":"ru/code-yeongyu/oh-my-opencode/start/index.md","filePath":"ru/code-yeongyu/oh-my-opencode/start/index.md"}'),i={name:"ru/code-yeongyu/oh-my-opencode/start/index.md"};function t(d,e,n,s,c,h){return r(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="быстрыи-старт" tabindex="-1">Быстрый старт <a class="header-anchor" href="#быстрыи-старт" aria-label="Permalink to &quot;Быстрый старт&quot;">​</a></h1><p>Этот раздел поможет вам быстро установить и начать использовать oh-my-opencode: от базовой настройки до основного оркестратора, а затем до режима Ultrawork, который активирует все функции одним щелчком.</p><h2 id="путь-обучения" tabindex="-1">Путь обучения <a class="header-anchor" href="#путь-обучения" aria-label="Permalink to &quot;Путь обучения&quot;">​</a></h2><p>Следуйте этой последовательности, чтобы постепенно освоить основные функции oh-my-opencode:</p><h3 id="_1-быстрая-установка-и-настроика" tabindex="-1">1. <a href="./installation/">Быстрая установка и настройка</a> <a class="header-anchor" href="#_1-быстрая-установка-и-настроика" aria-label="Permalink to &quot;1. [Быстрая установка и настройка](./installation/)&quot;">​</a></h3><p>Завершите установку oh-my-opencode, настройку Provider и базовую проверку.</p><ul><li>Установите oh-my-opencode</li><li>Настройте AI Provider (Claude, OpenAI, Gemini и др.)</li><li>Проверьте правильность конфигурации</li><li>Изучите структуру файла конфигурации</li></ul><h3 id="_2-познакомьтесь-с-сизифом-основным-оркестратором" tabindex="-1">2. <a href="./sisyphus-orchestrator/">Познакомьтесь с Сизифом: основным оркестратором</a> <a class="header-anchor" href="#_2-познакомьтесь-с-сизифом-основным-оркестратором" aria-label="Permalink to &quot;2. [Познакомьтесь с Сизифом: основным оркестратором](./sisyphus-orchestrator/)&quot;">​</a></h3><p>Поймите основные концепции оркестрации агентов и изучите базовое использование агента Сизифа.</p><ul><li>Что такое система оркестрации агентов</li><li>Основные функции агента Сизифа</li><li>Базовое использование и лучшие практики</li><li>Понимание рабочего процесса совместной работы нескольких моделей</li></ul><h3 id="_3-режим-ultrawork-активация-всех-функции-одним-щелчком" tabindex="-1">3. <a href="./ultrawork-mode/">Режим Ultrawork: активация всех функций одним щелчком</a> <a class="header-anchor" href="#_3-режим-ultrawork-активация-всех-функции-одним-щелчком" aria-label="Permalink to &quot;3. [Режим Ultrawork: активация всех функций одним щелчком](./ultrawork-mode/)&quot;">​</a></h3><p>Изучите, как использовать ключевое слово ultrawork для быстрой активации всех профессиональных агентов и функций параллельных задач.</p><ul><li>Что такое режим Ultrawork</li><li>Как вызвать ключевое слово ultrawork</li><li>Совместная работа 10 профессиональных агентов</li><li>Управление параллельными фоновыми задачами</li></ul><h2 id="предварительные-требования" tabindex="-1">Предварительные требования <a class="header-anchor" href="#предварительные-требования" aria-label="Permalink to &quot;Предварительные требования&quot;">​</a></h2><p>Перед началом работы с этим разделом убедитесь, что:</p><ul><li>Установлен Node.js 18+ (рекомендуется версия 20 или выше)</li><li>Вы знакомы с базовыми операциями командной строки</li><li>У вас есть хотя бы один ключ API AI-сервиса (Claude, OpenAI или Gemini)</li></ul><div class="tip custom-block"><p class="custom-block-title">Нет ключа API?</p><p>Если у вас ещё нет ключа API AI-сервиса, вы можете начать с заявки на Claude, который в настоящее время является наиболее рекомендуемым выбором.</p></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения этого раздела вы можете продолжить обучение:</p><ul><li><strong><a href="/docs/opencodedocs/ru/code-yeongyu/oh-my-opencode/platforms/provider-setup/">Платформы и интеграции</a></strong> — углублённое изучение настройки нескольких Provider и стратегий моделей</li><li><strong><a href="/docs/opencodedocs/ru/code-yeongyu/oh-my-opencode/advanced/ai-agents-overview/">Расширенные функции</a></strong> — изучение полной команды из 10 агентов и расширенных функций</li></ul>',20)])])}const m=o(i,[["render",t]]);export{p as __pageData,m as default};
